import strawberry
from sqlalchemy import create_engine
from sqlalchemy.orm import sessionmaker

@strawberry.type
class Product:
    id: int
    name: str
    description: str
    price: float
    reviews: List[Review]
    sellers: List[Seller]
    categories: List[Category]
    images: List[Image]

@strawberry.type
class Review:
    id: int
    rating: int
    comment: str
    product_id: int

@strawberry.type
class Seller:
    id: int
    name: str
    email: str
    products: List[Product]

@strawberry.type
class Category:
    id: int
    name: str
    description: str
    products: List[Product]

@strawberry.type
class Image:
    id: int
    url: str
    product_id: int

engine = create_engine("postgresql://user:password@host/database")
Session = sessionmaker(bind=engine)
session = Session()

products = session.query(Product).all()